package main

import (
	"context"
	"flag"
	"fmt"
	"os"
	"os/signal"
	"syscall"

	"k8s.io/klog/v2"

	"github.com/anomalyco/agentcube/pkg/picod"
)

func main() {
	port := flag.Int("port", 8080, "HTTP server port")
	workspace := flag.String("workspace", ".", "Workspace directory")
	klog.InitFlags(nil)
	flag.Parse()

	if *workspace == "" {
		*workspace, _ = os.Getwd()
	}

	cfg := &picod.Config{
		Port:      *port,
		Workspace: *workspace,
	}

	if publicKeyPEM := os.Getenv("PICOD_AUTH_PUBLIC_KEY"); publicKeyPEM != "" {
		pubKey, err := picod.LoadPublicKey("PICOD_AUTH_PUBLIC_KEY")
		if err != nil {
			klog.ErrorS(err, "Failed to load public key, auth disabled")
		} else {
			cfg.PublicKey = pubKey
			cfg.AuthEnabled = true
			klog.Info("JWT authentication enabled")
		}
	}

	srv := picod.NewServer(cfg)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		<-sigCh
		klog.Info("Shutting down server...")
		cancel()
	}()

	if err := srv.Run(ctx); err != nil {
		klog.ErrorS(err, "Server error")
		os.Exit(1)
	}
}

