	}

	c.JSON(http.StatusOK, gin.H{
		"subscriptions": subs,
		"count":         len(subs),
	})
}

func (s *Server) deleteSubscriptionHandler(c *gin.Context) {
	id := c.Param("id")
	if id == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "subscription ID is required"})
		return
	}

	s.mu.Lock()
	_, exists := s.subscriptions[id]
	if exists {
		delete(s.subscriptions, id)
	}
	s.mu.Unlock()

	if !exists {
		c.JSON(http.StatusNotFound, gin.H{"error": "subscription not found", "id": id})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"status": "deleted",
		"id":     id,
	})
}

func (s *Server) statsHandler(c *gin.Context) {
	s.mu.RLock()
	subCount := len(s.subscriptions)
	s.mu.RUnlock()

	c.JSON(http.StatusOK, gin.H{
		"queueSize":     len(s.queue),
		"queueCap":      cap(s.queue),
		"subscriptions": subCount,
		"workers":       s.workers,
		"uptime":        time.Since(s.startTime).String(),
	})
}

func (s *Server) startWorkers() {
	for i := 0; i < s.workers; i++ {
		s.wg.Add(1)
		go s.worker(i)
	}
}

func (s *Server) worker(id int) {
	defer s.wg.Done()

	for {
		select {
		case event := <-s.queue:
			s.processEvent(event)
		case <-s.stopCh:
			return
		}
	}
}

func (s *Server) processEvent(event *Event) {
	ctx := context.Background()

	handlers := s.getHandlers(event.Type)
	for _, handler := range handlers {
		if err := handler(ctx, event); err != nil {
			klog.ErrorS(err, "Event handler error",
				"eventId", event.ID,
				"eventType", event.Type,
			)
		}
	}

	s.mu.RLock()
	for _, sub := range s.subscriptions {
		if sub.Active && s.matchesSubscription(event, sub) {
			go s.dispatchToSubscriber(ctx, event, sub)
		}
	}
	s.mu.RUnlock()
}

func (s *Server) dispatchToSubscriber(ctx context.Context, event *Event, sub *Subscription) {
	client := &http.Client{Timeout: 10 * time.Second}

	eventData, err := serializeEvent(event)
	if err != nil {
		klog.ErrorS(err, "Failed to serialize event", "eventId", event.ID)
		return
	}

	req, err := http.NewRequestWithContext(ctx, "POST", sub.Endpoint, bytes.NewReader(eventData))
	if err != nil {
		klog.ErrorS(err, "Failed to create request", "endpoint", sub.Endpoint)
		return
	}
	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("X-Event-ID", event.ID)
	req.Header.Set("X-Event-Type", event.Type)

	resp, err := client.Do(req)
	if err != nil {
		klog.ErrorS(err, "Failed to dispatch event",
			"eventId", event.ID,
			"endpoint", sub.Endpoint,
		)
		return
	}
	defer resp.Body.Close()

	if resp.StatusCode >= 400 {
		klog.V(2).InfoS("Subscriber returned error",
			"eventId", event.ID,
			"subscriber", sub.ID,
			"status", resp.StatusCode,
		)
	}
}

func (s *Server) matchesSubscription(event *Event, sub *Subscription) bool {
	if len(sub.Events) == 0 {
		return true
	}

	for _, t := range sub.Events {
		if t == event.Type || t == "*" {
			return true
		}
	}
	return false
}

func (s *Server) getHandlers(eventType string) []EventHandler {
	s.mu.RLock()
	defer s.mu.RUnlock()

	return s.handlers[eventType]
}

func (s *Server) RegisterHandler(eventType string, handler EventHandler) {
	s.mu.Lock()
	defer s.mu.Unlock()

	s.handlers[eventType] = append(s.handlers[eventType], handler)
}

func (s *Server) Run(ctx context.Context) error {
	s.startWorkers()

	addr := fmt.Sprintf(":%d", s.config.Port)

	s.server = &http.Server{
		Addr:              addr,
		Handler:           s.router,
		ReadTimeout:       s.config.ReadTimeout,
		WriteTimeout:      s.config.WriteTimeout,
		ReadHeaderTimeout: DefaultReadHeaderTimeout,
	}

	errCh := make(chan error, 1)

	go func() {
		klog.InfoS("Starting Event Dispatcher server", "addr", addr)
		if err := s.server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			errCh <- err
		}
	}()

	select {
	case err := <-errCh:
		return err
	case <-ctx.Done():
		return s.Shutdown(context.Background())
	}
}

func (s *Server) Shutdown(ctx context.Context) error {
	close(s.stopCh)
	s.wg.Wait()

	if s.server != nil {
		klog.InfoS("Shutting down Event Dispatcher server")
		return s.server.Shutdown(ctx)
	}
	return nil
}

func (s *Server) Publish(event *Event) error {
	if event.ID == "" {
		event.ID = generateEventID()
	}
	if event.Timestamp.IsZero() {
		event.Timestamp = time.Now()
	}

	select {
	case s.queue <- event:
		return nil
	default:
		return fmt.Errorf("queue full")
	}
}

func (s *Server) GetQueueSize() int {
	return len(s.queue)
}

func generateEventID() string {
	return fmt.Sprintf("evt_%d", time.Now().UnixNano())
}

func generateSubscriptionID() string {
	return fmt.Sprintf("sub_%d", time.Now().UnixNano())
}

func serializeEvent(event *Event) ([]byte, error) {
	return []byte(fmt.Sprintf(`{"id":"%s","type":"%s"}`, event.ID, event.Type)), nil
}

type EventEmitter struct {
	server *Server
}

func NewEventEmitter(server *Server) *EventEmitter {
	return &EventEmitter{server: server}
}

func (e *EventEmitter) Emit(eventType string, payload map[string]interface{}) error {
	event := &Event{
		ID:        generateEventID(),
		Type:      eventType,
		Timestamp: time.Now(),
		Payload:   payload,
	}
	return e.server.Publish(event)
}

func (e *EventEmitter) EmitWithContext(ctx context.Context, eventType string, payload map[string]interface{}) error {
	return e.Emit(eventType, payload)
}

