package store

import (
	"context"
	"fmt"
	"strings"
	"time"

	"github.com/valkey-io/valkey-go"
	"k8s.io/klog/v2"

	"github.com/anomalyco/agentcube/pkg/common/types"
)

type ValkeyStore struct {
	client valkey.Client
}

func NewValkeyStore(cfg *Config) (*ValkeyStore, error) {
	if err := cfg.Validate(); err != nil {
		return nil, err
	}

	var client valkey.Client
	var err error

	if len(cfg.ClusterAddrs) > 0 && !cfg.ForceSingle {
		client, err = newValkeyClusterClient(cfg)
	} else {
		client, err = newValkeySingleClient(cfg)
	}

	if err != nil {
		return nil, fmt.Errorf("%w: %v", ErrConnectionFailed, err)
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := client.Do(ctx, client.B().Ping().Build()).Error(); err != nil {
		return nil, fmt.Errorf("%w: %v", ErrConnectionFailed, err)
	}

	klog.InfoS("Valkey store initialized", "addrs", cfg.Addr)
	return &ValkeyStore{client: client}, nil
}

func newValkeySingleClient(cfg *Config) (valkey.Client, error) {
	opts := valkey.ClientOption{
		Addr:     cfg.Addr,
		Password: cfg.Password,
		DB:       cfg.DB,
	}

	if cfg.DisableCache {
		opts.DisableCache = true
	}

	return valkey.NewClient(opts)
}

func newValkeyClusterClient(cfg *Config) (valkey.Client, error) {
	opts := valkey.ClusterOption{
		InitAddress: cfg.ClusterAddrs,
		Password:    cfg.Password,
	}

	if cfg.DisableCache {
		opts.DisableCache = true
	}

	return valkey.NewClusterClient(opts)
}

func (s *ValkeyStore) Ping(ctx context.Context) error {
	return s.client.Do(ctx, s.client.B().Ping().Build()).Error()
}

func (s *ValkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := fmt.Sprintf("%s%s", SessionKeyPrefix, sessionID)

	result := s.client.Do(ctx, s.client.B().Get().Key(key).Build())
	if result.Error() != nil {
		if valkey.IsRedisNil(result.Error()) {
			return nil, ErrSessionNotFound
		}
		return nil, fmt.Errorf("failed to get sandbox: %w", result.Error())
	}

	data, err := result.AsBytes()
	if err != nil {
		return nil, fmt.Errorf("failed to get sandbox data: %w", err)
	}

	var sandbox types.SandboxInfo
	if err := sandbox.Unmarshal(data); err != nil {
		return nil, fmt.Errorf("failed to unmarshal sandbox: %w", err)
	}

	return &sandbox, nil
}

func (s *ValkeyStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	key := fmt.Sprintf("%s%s", SessionKeyPrefix, sandbox.SessionID)

	data, err := sandbox.Marshal()
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	ttl := time.Until(sandbox.ExpiresAt)
	if ttl <= 0 {
		ttl = DefaultSessionTTL
	}

	expiryScore := sandbox.ExpiresAt.Unix()
	activityScore := sandbox.LastActivityAt.Unix()

	cmds := make([]valkey.Completed, 0, 3)
	cmds = append(cmds, s.client.B().Setnx().Key(key).Value(string(data)).Build())
	cmds = append(cmds, s.client.B().Zadd().Key(ExpiryIndexKey).ScoreMember().ScoreMember(valkey.Z{
		Score:  float64(expiryScore),
		Member: sandbox.SessionID,
	}).Build())
	cmds = append(cmds, s.client.B().Zadd().Key(LastActivityIndexKey).ScoreMember().ScoreMember(valkey.Z{
		Score:  float64(activityScore),
		Member: sandbox.SessionID,
	}).Build())

	for _, cmd := range cmds {
		if err := s.client.Do(ctx, cmd).Error(); err != nil {
			return fmt.Errorf("failed to store sandbox: %w", err)
		}
	}

	klog.V(2).InfoS("Stored sandbox", "sessionId", sandbox.SessionID, "ttl", ttl)
	return nil
}

func (s *ValkeyStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	key := fmt.Sprintf("%s%s", SessionKeyPrefix, sandbox.SessionID)

	data, err := sandbox.Marshal()
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	ttl := time.Until(sandbox.ExpiresAt)
	if ttl <= 0 {
		ttl = DefaultSessionTTL
	}

	setCmd := s.client.B().Set().Key(key).Value(string(data)).Ex(ttl).Xx().Build()
	result := s.client.Do(ctx, setCmd)
	if result.Error() != nil {
		return fmt.Errorf("failed to update sandbox: %w", result.Error())
	}

	ok, err := result.AsBool()
	if err != nil || !ok {
		return ErrSessionNotFound
	}

	activityScore := sandbox.LastActivityAt.Unix()
	zaddCmd := s.client.B().Zadd().Key(LastActivityIndexKey).ScoreMember().ScoreMember(valkey.Z{
		Score:  float64(activityScore),
		Member: sandbox.SessionID,
	}).Build()

	if err := s.client.Do(ctx, zaddCmd).Error(); err != nil {
		return fmt.Errorf("failed to update activity index: %w", err)
	}

	klog.V(2).InfoS("Updated sandbox", "sessionId", sandbox.SessionID)
	return nil
}

func (s *ValkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := fmt.Sprintf("%s%s", SessionKeyPrefix, sessionID)

	cmds := make([]valkey.Completed, 0, 3)
	cmds = append(cmds, s.client.B().Del().Key(key).Build())
	cmds = append(cmds, s.client.B().Zrem().Key(ExpiryIndexKey).Member(sessionID).Build())
	cmds = append(cmds, s.client.B().Zrem().Key(LastActivityIndexKey).Member(sessionID).Build())

	for _, cmd := range cmds {
		if err := s.client.Do(ctx, cmd).Error(); err != nil {
			return fmt.Errorf("failed to delete sandbox: %w", err)
		}
	}

	klog.V(2).InfoS("Deleted sandbox", "sessionId", sessionID)
	return nil
}

func (s *ValkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	maxScore := before.Unix()

	cmd := s.client.B().Zrangebyscore().Key(ExpiryIndexKey).Min("-inf").Max(fmt.Sprintf("%d", maxScore)).Count(limit).Build()
	result := s.client.Do(ctx, cmd)
	if result.Error() != nil {
		return nil, fmt.Errorf("failed to list expired sandboxes: %w", result.Error())
	}

	sessionIDs, err := result.AsStrSlice()
	if err != nil {
		return nil, fmt.Errorf("failed to parse session IDs: %w", err)
	}

	return s.fetchSandboxesByIDs(ctx, sessionIDs)
}

func (s *ValkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	maxScore := before.Unix()

	cmd := s.client.B().Zrangebyscore().Key(LastActivityIndexKey).Min("-inf").Max(fmt.Sprintf("%d", maxScore)).Count(limit).Build()
	result := s.client.Do(ctx, cmd)
	if result.Error() != nil {
		return nil, fmt.Errorf("failed to list inactive sandboxes: %w", result.Error())
	}

	sessionIDs, err := result.AsStrSlice()
	if err != nil {
		return nil, fmt.Errorf("failed to parse session IDs: %w", err)
	}

	return s.fetchSandboxesByIDs(ctx, sessionIDs)
}

func (s *ValkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	key := fmt.Sprintf("%s%s", SessionKeyPrefix, sessionID)

	existsCmd := s.client.B().Exists().Key(key).Build()
	result := s.client.Do(ctx, existsCmd)
	if result.Error() != nil {
		return fmt.Errorf("failed to check session existence: %w", result.Error())
	}

	count, err := result.AsInt64()
	if err != nil {
		return fmt.Errorf("failed to parse exists result: %w", err)
	}
	if count == 0 {
		return ErrSessionNotFound
	}

	score := at.Unix()
	zaddCmd := s.client.B().Zadd().Key(LastActivityIndexKey).ScoreMember().ScoreMember(valkey.Z{
		Score:  float64(score),
		Member: sessionID,
	}).Build()

	if err := s.client.Do(ctx, zaddCmd).Error(); err != nil {
		return fmt.Errorf("failed to update activity index: %w", err)
	}

	klog.V(2).InfoS("Updated session activity", "sessionId", sessionID, "at", at)
	return nil
}

func (s *ValkeyStore) fetchSandboxesByIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	sandboxes := make([]*types.SandboxInfo, 0, len(sessionIDs))
	for _, sessionID := range sessionIDs {
		sandbox, err := s.GetSandboxBySessionID(ctx, sessionID)
		if err != nil {
			if err == ErrSessionNotFound {
				continue
			}
			return nil, err
		}
		sandboxes = append(sandboxes, sandbox)
	}

	return sandboxes, nil
}

func (s *ValkeyStore) Close() error {
	if s.client != nil {
		return s.client.Close()
	}
	return nil
}

func splitValkeyAddrs(addrs string) []string {
	if addrs == "" {
		return nil
	}
	return strings.Split(addrs, ",")
}

