	ExpiresAtAnnotation    = "agentcube.io/expires-at"
	SessionIDLabel         = "agentcube.io/session-id"
	DefaultExpiryTimeout   = 15 * time.Minute
	DefaultRequeueAfter    = 1 * time.Minute
)

type Controller struct {
	manager       manager.Manager
	store         store.Store
	expiryTimeout time.Duration
	scheme        *runtime.Scheme
}

type Config struct {
	ExpiryTimeout time.Duration
