func NewConfig() *Config {
	return &Config{
		ExpiryTimeout: DefaultExpiryTimeout,
	}
}

func (c *Config) Validate() error {
	if c.ExpiryTimeout <= 0 {
		return fmt.Errorf("expiry timeout must be positive")
	}
	return nil
}

func NewController(mgr manager.Manager, store store.Store, cfg *Config) (*Controller, error) {
	if cfg == nil {
		cfg = NewConfig()
	}

	if err := cfg.Validate(); err != nil {
		return nil, fmt.Errorf("invalid config: %w", err)
	}

	return &Controller{
		manager:       mgr,
		store:         store,
		expiryTimeout: cfg.ExpiryTimeout,
		scheme:        mgr.GetScheme(),
	}, nil
}

func (c *Controller) SetupWithManager(mgr manager.Manager) error {
	return ctrl.NewControllerManagedBy(mgr).
		For(&Sandbox{}).
		Complete(c)
}

func (c *Controller) Reconcile(ctx context.Context, req reconcile.Request) (reconcile.Result, error) {
	log := ctrl.LoggerFrom(ctx)

	var sandbox Sandbox
	if err := c.manager.GetClient().Get(ctx, req.NamespacedName, &sandbox); err != nil {
		if errors.IsNotFound(err) {
			log.V(2).Info("Sandbox not found, assuming deleted")
			return reconcile.Result{}, nil
		}
		log.Error(err, "Failed to get sandbox")
		return reconcile.Result{}, err
	}

	if !sandbox.DeletionTimestamp.IsZero() {
		log.V(2).Info("Sandbox is being deleted, skipping")
		return reconcile.Result{}, nil
	}

	if c.isExpired(&sandbox) {
		log.Info("Sandbox expired, deleting", "name", sandbox.Name, "namespace", sandbox.Namespace)
		if err := c.deleteSandbox(ctx, &sandbox); err != nil {
			if errors.IsNotFound(err) {
				return reconcile.Result{}, nil
			}
			log.Error(err, "Failed to delete expired sandbox")
			return reconcile.Result{RequeueAfter: DefaultRequeueAfter}, err
		}

		if err := c.cleanupStore(ctx, &sandbox); err != nil {
			log.V(2).Info("Failed to cleanup store", "error", err)
		}

