func (c *Controller) isExpired(sandbox *Sandbox) bool {
	lastActivityStr := sandbox.Annotations[LastActivityAnnotation]
	if lastActivityStr == "" {
		lastActivityStr = sandbox.Annotations[CreatedAtAnnotation]
	}

	if lastActivityStr == "" {
		if !sandbox.CreationTimestamp.IsZero() {
			return time.Since(sandbox.CreationTimestamp.Time) > c.expiryTimeout
		}
		return false
	}

	lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
	if err != nil {
		klog.V(2).InfoS("Failed to parse last activity time", "annotation", lastActivityStr, "error", err)
		if !sandbox.CreationTimestamp.IsZero() {
			return time.Since(sandbox.CreationTimestamp.Time) > c.expiryTimeout
		}
		return false
	}

	return time.Since(lastActivity) > c.expiryTimeout
