func (c *Controller) calculateRequeueAfter(sandbox *Sandbox) time.Duration {
	lastActivityStr := sandbox.Annotations[LastActivityAnnotation]
	if lastActivityStr == "" {
		lastActivityStr = sandbox.Annotations[CreatedAtAnnotation]
	}

	var lastActivity time.Time
	if lastActivityStr != "" {
		if parsed, err := time.Parse(time.RFC3339, lastActivityStr); err == nil {
			lastActivity = parsed
		}
	}

	if lastActivity.IsZero() {
		lastActivity = sandbox.CreationTimestamp.Time
	}

	if lastActivity.IsZero() {
		return DefaultRequeueAfter
	}

	expiresAt := lastActivity.Add(c.expiryTimeout)
	timeUntilExpiry := time.Until(expiresAt)

	if timeUntilExpiry <= 0 {
