	var lastActivity time.Time
	if lastActivityStr := sandbox.Annotations[LastActivityAnnotation]; lastActivityStr != "" {
		if parsed, err := time.Parse(time.RFC3339, lastActivityStr); err == nil {
			lastActivity = parsed
		}
	}

	var expiresAt time.Time
	if expiresAtStr := sandbox.Annotations[ExpiresAtAnnotation]; expiresAtStr != "" {
		if parsed, err := time.Parse(time.RFC3339, expiresAtStr); err == nil {
			expiresAt = parsed
		}
	}

	return &types.SandboxInfo{
		SessionID:      sessionID,
		Name:           sandbox.Name,
		Namespace:      sandbox.Namespace,
		Labels:         sandbox.Labels,
		Annotations:    sandbox.Annotations,
		CreatedAt:      sandbox.CreationTimestamp.Time,
		LastActivityAt: lastActivity,
		ExpiresAt:      expiresAt,
		PodIP:          sandbox.Status.PodIP,
	}
}

