	ticker := time.NewTicker(DefaultRequeueAfter)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			return nil
		case <-ticker.C:
			if err := c.cleanupExpiredSessions(ctx); err != nil {
