	before := time.Now().Add(-c.expiryTimeout)
	sandboxes, err := c.store.ListInactiveSandboxes(ctx, before, 100)
	if err != nil {
		return fmt.Errorf("failed to list inactive sandboxes: %w", err)
	}

	for _, sandbox := range sandboxes {
