func (c *K8sClient) buildAnnotations(sandbox *types.SandboxInfo) map[string]string {
	annotations := make(map[string]string)
	for k, v := range sandbox.Annotations {
		annotations[k] = v
	}
	annotations["agentcube.io/session-id"] = sandbox.SessionID
	annotations["agentcube.io/created-at"] = sandbox.CreatedAt.Format(time.RFC3339)
	annotations["agentcube.io/expires-at"] = sandbox.ExpiresAt.Format(time.RFC3339)
	annotations["agentcube.io/last-activity"] = sandbox.LastActivityAt.Format(time.RFC3339)
	return annotations
}

