func (c *K8sClient) WaitForPodReady(ctx context.Context, namespace, name string, timeout time.Duration) error {
	timeoutCtx, cancel := context.WithTimeout(ctx, timeout)
	defer cancel()

	for {
		select {
		case <-timeoutCtx.Done():
			return fmt.Errorf("timeout waiting for pod %s/%s to be ready", namespace, name)
		case <-time.After(1 * time.Second):
			pod, err := c.GetPod(timeoutCtx, namespace, name)
			if err != nil {
				return err
			}

			if pod.Status.Phase == corev1.PodRunning {
				for _, cond := range pod.Status.Conditions {
