func (s *Server) setupRoutes() {
	s.router.Use(s.loggingMiddleware())
	s.router.Use(gin.Recovery())

	if s.config.EnableAuth {
		s.router.Use(s.authMiddleware())
	}

	s.router.GET("/health", s.healthHandler)

	v1 := s.router.Group("/v1")
	{
		v1.POST("/agent-runtime", s.createAgentRuntime)
		v1.DELETE("/agent-runtime/sessions/:sessionId", s.deleteAgentRuntimeSession)
		v1.POST("/code-interpreter", s.createCodeInterpreter)
		v1.DELETE("/code-interpreter/sessions/:sessionId", s.deleteCodeInterpreterSession)
	}
