			c.JSON(http.StatusBadRequest, gin.H{"error": "template must specify at least one container"})
			return
		}
	}

	podName, err := s.k8sClient.CreateAgentRuntime(c.Request.Context(), sandbox, req.Template, s.config.RuntimeClassName)
	if err != nil {
