		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to create agent runtime", "detail": err.Error()})
		return
	}

	sandbox.PodName = podName

	if err := s.store.StoreSandbox(c.Request.Context(), sandbox); err != nil {
