	if sandbox.Labels == nil {
		return entryPoints
	}

	if portsJSON, ok := sandbox.Annotations["ports"]; ok {
		var ports []types.SandboxEntryPoint
		if err := json.Unmarshal([]byte(portsJSON), &ports); err == nil {
			entryPoints = ports
		}
	}

	return entryPoints
