		Handler:           s.router,
		ReadTimeout:       s.config.ReadTimeout,
		WriteTimeout:      s.config.WriteTimeout,
		ReadHeaderTimeout: DefaultReadHeaderTimeout,
	}

	errCh := make(chan error, 1)

	go func() {
		klog.InfoS("Starting Workload Manager server", "addr", addr)

		var err error
		if s.config.EnableTLS {
			err = s.server.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
		} else {
			err = s.server.ListenAndServe()
		}

		if err != nil && err != http.ErrServerClosed {
			errCh <- err
		}
	}()

	select {
	case err := <-errCh:
		return err
	case <-ctx.Done():
		return s.Shutdown(context.Background())
	}
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.server != nil {
		klog.InfoS("Shutting down Workload Manager server")
		return s.server.Shutdown(ctx)
	}
	return nil
}

func (s *Server) GetHTTPClient() (*http.Client, error) {
	if !s.config.EnableTLS {
		return http.DefaultClient, nil
	}

	cert, err := os.ReadFile(s.config.TLSCert)
	if err != nil {
		return nil, fmt.Errorf("failed to read TLS certificate: %w", err)
	}

	caCertPool := x509.NewCertPool()
	caCertPool.AppendCertsFromPEM(cert)

	tlsConfig := &tls.Config{
		RootCAs: caCertPool,
	}

	transport := &http.Transport{
		TLSClientConfig: tlsConfig,
	}

	return &http.Client{
		Transport: transport,
		Timeout:   30 * time.Second,
	}, nil
}

func WriteJSONError(c *gin.Context, status int, err error) {
	if apiErr := api.GetAPIError(err); apiErr != nil {
		c.JSON(apiErr.Code, gin.H{
			"error":  apiErr.Message,
			"detail": apiErr.Detail,
		})
		return
	}

	c.JSON(status, gin.H{
		"error": err.Error(),
	})
}

