	"github.com/anomalyco/agentcube/pkg/agentd"
	"github.com/anomalyco/agentcube/pkg/store"
)

func main() {
	var metricsAddr string
	var enableLeaderElection bool
	var probeAddr string
	var expiryTimeout time.Duration

	flag.StringVar(&metricsAddr, "metrics-bind-address", ":8080", "The address the metric endpoint binds to.")
	flag.StringVar(&probeAddr, "health-probe-bind-address", ":8081", "The address the probe endpoint binds to.")
	flag.BoolVar(&enableLeaderElection, "leader-elect", false, "Enable leader election for controller manager.")
	flag.DurationVar(&expiryTimeout, "expiry-timeout", 15*time.Minute, "Timeout for idle sandbox cleanup.")
	klog.InitFlags(nil)
	flag.Parse()

	ctrl.SetLogger(zap.New(zap.UseDevMode(true)))

	klog.InfoS("Starting AgentD", "metricsAddr", metricsAddr, "expiryTimeout", expiryTimeout)

	scheme := runtime.NewScheme()
	if err := corev1.AddToScheme(scheme); err != nil {
		klog.ErrorS(err, "Failed to add core/v1 to scheme")
		os.Exit(1)
	}

	mgr, err := ctrl.NewManager(ctrl.GetConfigOrDie(), ctrl.Options{
		Scheme:                 scheme,
		MetricsBindAddress:     metricsAddr,
		Port:                   9443,
		HealthProbeBindAddress: probeAddr,
		LeaderElection:         enableLeaderElection,
		LeaderElectionID:       "agentd.agentcube.io",
	})
	if err != nil {
		klog.ErrorS(err, "Unable to start manager")
		os.Exit(1)
	}

	storeCfg := store.NewConfigFromEnv()
	if err := store.InitStore(storeCfg); err != nil {
		klog.ErrorS(err, "Failed to initialize store")
		os.Exit(1)
	}
	defer store.Close()

	s := store.Storage()

	controllerCfg := &agentd.Config{
		ExpiryTimeout: expiryTimeout,
	}

	controller, err := agentd.NewController(mgr, s, controllerCfg)
	if err != nil {
		klog.ErrorS(err, "Failed to create controller")
		os.Exit(1)
	}

	if err := controller.SetupWithManager(mgr); err != nil {
		klog.ErrorS(err, "Unable to setup controller with manager")
		os.Exit(1)
	}

	if err := mgr.AddHealthzCheck("healthz", healthz.Ping); err != nil {
		klog.ErrorS(err, "Unable to set up health check")
		os.Exit(1)
	}

	if err := mgr.AddReadyzCheck("readyz", healthz.Ping); err != nil {
		klog.ErrorS(err, "Unable to set up ready check")
		os.Exit(1)
	}

	klog.InfoS("Starting manager")

	if err := mgr.Start(ctrl.SetupSignalHandler()); err != nil {
		klog.ErrorS(err, "Problem running manager")
		os.Exit(1)
	}

	klog.InfoS("AgentD stopped gracefully")
}

